(window.webpackJsonp=window.webpackJsonp||[]).push([[453],{1080:function(n,r){n.exports='\x3c!-- \r\ntitle: 00-快速入门\r\nsort: \r\n--\x3e \r\n# 前端快速入门\r\n\r\n## HTML\r\n\r\n```html\r\n<h2>hello</h2>\r\n<button>按钮</button>\r\n```\r\n\r\n## CSS\r\n\r\n```html\r\n<h2 style="color: red">hello</h2>\r\n<button>按钮</button>\r\n```\r\n\r\n### 使用标签\r\n\r\n```html\r\n<style>\r\n    .blue {\r\n        color: blue\r\n    }\r\n</style>\r\n<h2 class="blue">hello</h2>\r\n<button>按钮</button>\r\n```\r\n\r\n## JavaScript\r\n\r\n```html\r\n<button onclick="javascript:alert(\'hello\')">按钮</button>\r\n```\r\n\r\n### 使用标签\r\n\r\n```html\r\n<button onclick="func1()">按钮</button>\r\n<script>\r\n    function func1() {\r\n        alert(\'hello\')\r\n    }\r\n<\/script>\r\n```\r\n\r\n## Bootstrap\r\n\r\n```html\r\n<link href="https://cdn.bootcdn.net/ajax/libs/twitter-bootstrap/4.5.0/css/bootstrap.css" rel="stylesheet">\r\n\x3c!--添加cdn的link--\x3e\r\n<button class="btn btn-info">按钮</button>\r\n```\r\n\r\n## Jquery\r\n\r\n```html\r\n<link href="https://cdn.bootcdn.net/ajax/libs/twitter-bootstrap/4.5.0/css/bootstrap.css" rel="stylesheet">\r\n<script src="https://cdn.bootcdn.net/ajax/libs/jquery/3.5.1/jquery.js"><\/script>\r\n<h2 id=\'h\'>hello</h2>\r\n<button id=\'b1\' class="btn btn-info">隐藏标题</button>\r\n<button id=\'b2\' class="btn btn-warning">显示标题</button>\r\n<script>\r\n    $(\'#b1\').click(function () { $(\'#h\').hide(\'slow\') })\r\n    //点击b1按钮使h隐藏\r\n    $(\'#b2\').click(function () { $(\'#h\').show(\'slow\') })\r\n<\/script>\r\n```\r\n\r\n'}}]);